// // When reset is low, the register loads the value from the data input when load is high.
module parallel_load_register (
    input clk,
    input reset,
    input load,
    input [7:0] data,
    output reg [7:0] q
);always @(posedge clk) begin
        if (reset)
            q <= 8'b00000000;
        else if (load)
            q <= data;
    end

endmodule
